settings.custom_liquid:
{%- comment -%}
  Expired Film Club Landing Page
  Brooklyn Film Camera — Shopify Custom Liquid Section
  Fonts: Cormorant Garamond (display) + Poppins (body/UI)
  Brand palette from BFC Brand Kit
  Style: Sharp/modern — no border-radius
{%- endcomment -%}

<div class="efc">

  <!-- ═══════════════════════════════════════════
       ANNOUNCEMENT STRIP
  ═══════════════════════════════════════════ -->
  <div class="efc-announce" role="banner">
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
    Free shipping on all subscriptions — cancel or pause anytime
  </div>

  <!-- ═══════════════════════════════════════════
       HERO
  ═══════════════════════════════════════════ -->
  <section class="efc-hero" aria-labelledby="efc-hero-title">
    <div class="efc-wrap efc-hero__inner">
      <div class="efc-hero__copy">
        <span class="efc-badge">Limited stock · Ships from NYC</span>

        <h1 id="efc-hero-title" class="efc-hero__title">
          Expired<br>
          <em>Film Club</em>
        </h1>

        <p class="efc-hero__body">
          Monthly boxes of hand-picked expired film from trusted sources — rare stocks, beautiful results, and the occasional happy accident. Choose monthly or every 3 months.
        </p>

        <div class="efc-hero__actions">
          <a class="efc-btn efc-btn--primary" href="#efc-subscribe">Join the Club</a>
          <a class="efc-btn efc-btn--ghost" href="/account">My Membership</a>
        </div>

        <p class="efc-hero__cancel">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg>
          Cancel anytime
        </p>

        <div class="efc-hero__stats">
          <div class="efc-stat">
            <strong class="efc-stat__n">6k+</strong>
            <span class="efc-stat__label">Rolls sold</span>
          </div>
          <div class="efc-stat__divider" aria-hidden="true"></div>
          <div class="efc-stat">
            <strong class="efc-stat__n">100%</strong>
            <span class="efc-stat__label">Happy customers</span>
          </div>
          <div class="efc-stat__divider" aria-hidden="true"></div>
          <div class="efc-stat">
            <strong class="efc-stat__n">Rare</strong>
            <span class="efc-stat__label">Stocks every box</span>
          </div>
        </div>
      </div>

      <div class="efc-hero__media">
        <div class="efc-hero__img-frame">
          <img
            src="https://cdn.shopify.com/s/files/1/0575/8638/5068/files/Film_Club_Hero_3.jpg?v=1774565402"
            alt="Assortment of expired film rolls"
            loading="eager"
            width="600"
            height="480"
          >
        </div>
      </div>
    </div>
  </section>

  <!-- ═══════════════════════════════════════════
       SUBSCRIBE
  ═══════════════════════════════════════════ -->
  <section id="efc-subscribe" class="efc-subscribe" aria-labelledby="efc-subscribe-title">
    <div class="efc-wrap">
      <div class="efc-section-header">
        <h2 id="efc-subscribe-title" class="efc-section-title">Pick your format</h2>
        <p class="efc-section-sub">3 curated rolls per box · Cancel anytime</p>
      </div>

      <div class="efc-cards">

        <!-- 35mm -->
        <article class="efc-card">
          <div class="efc-card__media">
            <img
              src="https://cdn.shopify.com/s/files/1/0575/8638/5068/files/expiredfilm35mm.jpg?v=1774565543"
              alt="35mm expired film rolls"
              loading="lazy"
              width="480"
              height="320"
            >
          </div>
          <div class="efc-card__body">
            <div class="efc-card__top">
              <h3 class="efc-card__title">35mm</h3>
              <p class="efc-card__desc">Reliable, versatile — the everyday workhorse of expired film.</p>
            </div>
            <div class="efc-card__pricing">
              <span class="efc-price__amount">$36.00 <span class="efc-price__per">/mo</span> <span class="efc-tag">10% off</span></span>
              <p class="efc-price__alt">or $40 billed every 3 months</p>
            </div>
            <div class="efc-card__actions">
              <a class="efc-btn efc-btn--primary efc-btn--full"
                href="https://brooklyn-film-camera.myshopify.com/cart/clear?return_to=/cart/add?items[][id]=44717797441708%26items[][quantity]=1%26items[][selling_plan]=2987491500%26return_to=/checkout">
                Monthly
              </a>
              <a class="efc-btn efc-btn--outline efc-btn--full"
                href="https://brooklyn-film-camera.myshopify.com/cart/clear?return_to=/cart/add?items[][id]=44717797441708%26items[][quantity]=1%26items[][selling_plan]=2987458732%26return_to=/checkout">
                Every 3 months
              </a>
            </div>
          </div>
        </article>

        <!-- 120 -->
        <article class="efc-card">
          <div class="efc-card__media">
            <img
              src="https://cdn.shopify.com/s/files/1/0575/8638/5068/files/expiredfilm120.jpg?v=1774565544"
              alt="120 medium format expired film rolls"
              loading="lazy"
              width="480"
              height="320"
            >
          </div>
          <div class="efc-card__body">
            <div class="efc-card__top">
              <h3 class="efc-card__title">120</h3>
              <p class="efc-card__desc">Bigger negatives, dreamier detail. For the medium format devotee.</p>
            </div>
            <div class="efc-card__pricing">
              <span class="efc-price__amount">$45.00 <span class="efc-price__per">/mo</span> <span class="efc-tag">10% off</span></span>
              <p class="efc-price__alt">or $50 billed every 3 months</p>
            </div>
            <div class="efc-card__actions">
              <a class="efc-btn efc-btn--primary efc-btn--full"
                href="https://brooklyn-film-camera.myshopify.com/cart/clear?return_to=/cart/add?items[][id]=44717797474476%26items[][quantity]=1%26items[][selling_plan]=2987491500%26return_to=/checkout">
                Monthly
              </a>
              <a class="efc-btn efc-btn--outline efc-btn--full"
                href="https://brooklyn-film-camera.myshopify.com/cart/clear?return_to=/cart/add?items[][id]=44717797474476%26items[][quantity]=1%26items[][selling_plan]=2987458732%26return_to=/checkout">
                Every 3 months
              </a>
            </div>
          </div>
        </article>

        <!-- Combo -->
        <article class="efc-card">
          <div class="efc-card__media">
            <img
              src="https://cdn.shopify.com/s/files/1/0575/8638/5068/files/expiredfilmgroup.jpg?v=1774565544"
              alt="Combo expired film assortment"
              loading="lazy"
              width="480"
              height="320"
            >
          </div>
          <div class="efc-card__body">
            <div class="efc-card__top">
              <h3 class="efc-card__title">Combo</h3>
              <p class="efc-card__desc">A rotating mix of 35mm &amp; 120 — curated for happy accidents.</p>
            </div>
            <div class="efc-card__pricing">
              <span class="efc-price__amount">$40.50 <span class="efc-price__per">/mo</span> <span class="efc-tag">10% off</span></span>
              <p class="efc-price__alt">or $45 billed every 3 months</p>
            </div>
            <div class="efc-card__actions">
              <a class="efc-btn efc-btn--primary efc-btn--full"
                href="https://brooklyn-film-camera.myshopify.com/cart/clear?return_to=/cart/add?items[][id]=44717797507244%26items[][quantity]=1%26items[][selling_plan]=2987491500%26return_to=/checkout">
                Monthly
              </a>
              <a class="efc-btn efc-btn--outline efc-btn--full"
                href="https://brooklyn-film-camera.myshopify.com/cart/clear?return_to=/cart/add?items[][id]=44717797507244%26items[][quantity]=1%26items[][selling_plan]=2987458732%26return_to=/checkout">
                Every 3 months
              </a>
            </div>
          </div>
        </article>

      </div>

      <p class="efc-subscribe__note">Cancel or pause anytime · No commitment</p>
    </div>
  </section>

  <!-- ═══════════════════════════════════════════
       WHAT'S IN THE BOX
  ═══════════════════════════════════════════ -->
  <section class="efc-inbox" aria-labelledby="efc-inbox-title">
    <div class="efc-wrap efc-inbox__inner">

      <div class="efc-inbox__media">
        <figure class="efc-inbox__frame">
          <img
            src="https://cdn.shopify.com/s/files/1/0575/8638/5068/files/EX_50__Expired_P160_403_SQ_1.jpg?v=1756574725"
            alt="Contents of an Expired Film Club box"
            loading="lazy"
            width="560"
            height="560"
          >
        </figure>
      </div>

      <div class="efc-inbox__copy">
        <span class="efc-eyebrow">What's in every box</span>
        <h2 id="efc-inbox-title" class="efc-inbox__title">
          Curated with<br><em>intention</em>
        </h2>
        <p class="efc-inbox__body">
          Every shipment is hand-picked from trusted sources. We focus on rolls with reliable results and genuine character — plus the occasional rare stock you won't find anywhere else.
        </p>

        <ul class="efc-inbox__list" role="list">
          <li><span class="efc-list-icon" aria-hidden="true">◆</span>3 curated rolls per box</li>
          <li><span class="efc-list-icon" aria-hidden="true">◆</span>Rare &amp; hard-to-find stocks</li>
          <li><span class="efc-list-icon" aria-hidden="true">◆</span>Both 35mm and 120 available</li>
          <li><span class="efc-list-icon" aria-hidden="true">◆</span>Free shipping — ships from Brooklyn, NYC</li>
        </ul>

        <a class="efc-btn efc-btn--primary" href="#efc-subscribe">Choose your box</a>
      </div>

    </div>
  </section>

  <!-- ═══════════════════════════════════════════
       BOTTOM CTA
  ═══════════════════════════════════════════ -->
  <section class="efc-cta" aria-labelledby="efc-cta-title">
    <div class="efc-wrap">
      <div class="efc-cta__card">
        <div class="efc-cta__copy">
          <h2 id="efc-cta-title" class="efc-cta__title">Looking for a specific stock?</h2>
          <p class="efc-cta__sub">Browse our full selection of expired films — sold individually.</p>
        </div>
        <a class="efc-btn efc-btn--dark" href="/collections/expired-film">Shop All Expired Film</a>
      </div>
    </div>
