</div><!-- /efc -->

{% style %}
/* ─────────────────────────────────────────
   FONTS
───────────────────────────────────────── */
@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,500;0,600;1,500;1,600&family=Poppins:wght@400;500;600&display=swap');

/* ─────────────────────────────────────────
   TOKENS
───────────────────────────────────────── */
.efc {
  --efc-canvas:   #F8F6EE;
  --efc-orange:   #E36E15;
  --efc-gold:     #F4A027;
  --efc-brown:    #5A3E2D;
  --efc-black:    #202009;
  --efc-charcoal: #4E4741;
  --efc-gray:     #E3DDDA;
  --efc-manila:   #FFEACC;
  --efc-muted:    #7A6F68;

  --efc-font-display: 'Cormorant Garamond', Georgia, serif;
  --efc-font-body:    'Poppins', system-ui, sans-serif;
  --efc-gap: clamp(56px, 8vw, 88px);

  font-family: var(--efc-font-body);
  color: var(--efc-black);
  background: var(--efc-canvas);
  -webkit-font-smoothing: antialiased;
}

/* ─────────────────────────────────────────
   ANNOUNCEMENT STRIP
───────────────────────────────────────── */
.efc-announce {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  background: var(--efc-black);
  color: var(--efc-canvas);
  font-family: var(--efc-font-body);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: .1em;
  text-transform: uppercase;
  padding: 10px 16px;
}
.efc-announce svg {
  flex-shrink: 0;
  opacity: .6;
}

/* ─────────────────────────────────────────
   LAYOUT
───────────────────────────────────────── */
.efc-wrap {
  max-width: 1140px;
  margin-inline: auto;
  padding-inline: clamp(16px, 4vw, 40px);
}

/* ─────────────────────────────────────────
   SHARED
───────────────────────────────────────── */
.efc-eyebrow {
  display: block;
  font-size: 10.5px;
  font-weight: 600;
  letter-spacing: .16em;
  text-transform: uppercase;
  color: var(--efc-orange);
  margin-bottom: 14px;
}
.efc-section-title {
  font-family: var(--efc-font-display);
  font-size: clamp(28px, 4.5vw, 42px);
  font-weight: 600;
  line-height: 1.05;
  margin: 0;
  color: var(--efc-black);
}
.efc-section-sub {
  font-size: 12.5px;
  color: var(--efc-muted);
  margin: 0;
}
.efc-section-header {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  border-bottom: 1px solid var(--efc-gray);
  padding-bottom: 18px;
  margin-bottom: 36px;
  flex-wrap: wrap;
  gap: 8px;
}

/* Buttons — zero border-radius */
.efc-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: .5ch;
  padding: 11px 22px;
  border-radius: 0;
  border: 1.5px solid transparent;
  font-family: var(--efc-font-body);
  font-size: 11.5px;
  font-weight: 600;
  letter-spacing: .08em;
  text-transform: uppercase;
  text-decoration: none;
  cursor: pointer;
  transition: background .15s, color .15s, border-color .15s;
  white-space: nowrap;
}
.efc-btn--primary  { background: var(--efc-orange); color: #fff; border-color: var(--efc-orange); }
.efc-btn--primary:hover { background: #c95e0f; border-color: #c95e0f; }
.efc-btn--ghost    { background: transparent; color: var(--efc-black); border-color: rgba(32,32,9,.28); }
.efc-btn--ghost:hover { background: rgba(32,32,9,.04); }
.efc-btn--outline  { background: transparent; color: var(--efc-black); border-color: rgba(32,32,9,.28); }
.efc-btn--outline:hover { background: rgba(32,32,9,.04); }
.efc-btn--dark     { background: var(--efc-black); color: var(--efc-canvas); border-color: var(--efc-black); }
.efc-btn--dark:hover { background: #3a3a1a; }
.efc-btn--full { width: 100%; }

/* Badge */
.efc-badge {
  display: inline-flex;
  align-items: center;
  padding: 4px 12px;
  background: var(--efc-manila);
  color: var(--efc-brown);
  font-size: 10.5px;
  font-weight: 600;
  letter-spacing: .07em;
  text-transform: uppercase;
}

/* Tag */
.efc-tag {
  display: inline-block;
  padding: 2px 8px;
  background: #E6F4E0;
  color: #2D6A1F;
  font-size: 9.5px;
  font-weight: 600;
  letter-spacing: .04em;
  margin-left: 6px;
  vertical-align: middle;
}

/* ─────────────────────────────────────────
   HERO
───────────────────────────────────────── */
.efc-hero {
  background: var(--efc-canvas);
  border-bottom: 1px solid var(--efc-gray);
  padding-block: clamp(64px, 10vw, 96px) clamp(56px, 8vw, 80px);
}
.efc-hero__inner {
  display: grid;
  grid-template-columns: 1fr;
  gap: 48px;
  align-items: center;
}
@media (min-width: 900px) {
  .efc-hero__inner { grid-template-columns: 1fr 1fr; gap: 64px; }
}
.efc-hero__title {
  font-family: var(--efc-font-display);
  font-size: clamp(52px, 9vw, 88px);
  font-weight: 600;
  line-height: 1.0;
  margin: 16px 0 20px;
  color: var(--efc-black);
}
.efc-hero__title em { font-style: italic; color: var(--efc-orange); }
.efc-hero__body {
  font-size: clamp(14px, 1.8vw, 16px);
  line-height: 1.72;
  color: var(--efc-charcoal);
  max-width: 52ch;
  margin: 0 0 26px;
}
.efc-hero__actions {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-bottom: 14px;
}
.efc-hero__cancel {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11.5px;
  color: var(--efc-muted);
  margin: 0 0 30px;
}
.efc-hero__stats {
  display: flex;
  align-items: stretch;
  border: 1px solid var(--efc-gray);
  background: #fff;
  max-width: 440px;
}
.efc-stat {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  padding: 16px 0;
  gap: 3px;
}
.efc-stat__n {
  font-family: var(--efc-font-display);
  font-size: 30px;
  font-weight: 600;
  line-height: 1;
  color: var(--efc-black);
}
.efc-stat__label {
  font-size: 9.5px;
  color: var(--efc-muted);
  text-transform: uppercase;
  letter-spacing: .08em;
  font-weight: 500;
}
.efc-stat__divider {
  width: 1px;
  background: var(--efc-gray);
  flex-shrink: 0;
}
.efc-hero__img-frame {
  overflow: hidden;
  aspect-ratio: 5 / 4;
  background: var(--efc-gray);
}
.efc-hero__img-frame img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* ─────────────────────────────────────────
   SUBSCRIBE
───────────────────────────────────────── */
.efc-subscribe {
  background: #fff;
  border-bottom: 1px solid var(--efc-gray);
  padding-block: var(--efc-gap);
}
.efc-cards {
  display: grid;
  grid-template-columns: 1fr;
  gap: 0;
  border: 1px solid var(--efc-gray);
}
@media (min-width: 680px) {
  .efc-cards { grid-template-columns: repeat(3, 1fr); }
}
.efc-card {
  display: flex;
  flex-direction: column;
  background: var(--efc-canvas);
  border-right: 1px solid var(--efc-gray);
  border-bottom: 1px solid var(--efc-gray);
  position: relative;
}
@media (min-width: 680px) {
  .efc-card:last-child { border-right: none; }
}
.efc-card__media {
  width: 100%;
  aspect-ratio: 16 / 10;
  overflow: hidden;
  background: var(--efc-gray);
  border-bottom: 1px solid var(--efc-gray);
}
.efc-card__media img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  transition: transform .3s ease;
}
.efc-card:hover .efc-card__media img { transform: scale(1.03); }
.efc-card__body {
  display: flex;
  flex-direction: column;
  flex: 1;
  padding: 20px;
  gap: 16px;
}
.efc-card__title {
  font-family: var(--efc-font-display);
  font-size: 26px;
  font-weight: 600;
  margin: 0 0 4px;
  color: var(--efc-black);
}
.efc-card__desc {
  font-size: 13px;
  color: var(--efc-muted);
  line-height: 1.5;
  margin: 0;
}
.efc-card__pricing { display: flex; flex-direction: column; gap: 5px; margin-top: auto; }
.efc-price__amount {
  font-family: var(--efc-font-display);
  font-size: 30px;
  font-weight: 600;
  line-height: 1;
  display: block;
}
.efc-price__per { font-size: 12px; color: var(--efc-muted); }
.efc-price__alt { font-size: 11.5px; color: var(--efc-muted); margin: 0; }
.efc-card__actions {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.efc-subscribe__note {
  margin-top: 20px;
  text-align: center;
  font-size: 11.5px;
  color: var(--efc-muted);
  letter-spacing: .03em;
}

/* ─────────────────────────────────────────
   INBOX (dark section)
───────────────────────────────────────── */
.efc-inbox {
  background: var(--efc-black);
  color: var(--efc-canvas);
  padding-block: var(--efc-gap);
}
.efc-inbox__inner {
  display: grid;
  grid-template-columns: 1fr;
  gap: 48px;
  align-items: center;
}
@media (min-width: 900px) {
  .efc-inbox__inner { grid-template-columns: 1fr 1fr; gap: 72px; }
}
.efc-inbox__frame {
  overflow: hidden;
  aspect-ratio: 1;
  background: var(--efc-charcoal);
  margin: 0;
}
.efc-inbox__frame img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}
.efc-inbox .efc-eyebrow { color: var(--efc-gold); }
.efc-inbox__title {
  font-family: var(--efc-font-display);
  font-size: clamp(36px, 5.5vw, 58px);
  font-weight: 600;
  line-height: 1.04;
  margin: 0 0 18px;
  color: var(--efc-canvas);
}
.efc-inbox__title em { font-style: italic; color: var(--efc-gold); }
.efc-inbox__body {
  font-size: 14.5px;
  line-height: 1.72;
  color: rgba(248,246,238,.65);
  margin: 0 0 22px;
  max-width: 48ch;
}
.efc-inbox__list {
  list-style: none;
  padding: 0;
  margin: 0 0 32px;
  border-top: 1px solid rgba(248,246,238,.1);
}
.efc-inbox__list li {
  display: flex;
  align-items: center;
  gap: 12px;
  font-size: 13.5px;
  color: rgba(248,246,238,.8);
  padding: 11px 0;
  border-bottom: 1px solid rgba(248,246,238,.1);
}
.efc-list-icon { color: var(--efc-gold); font-size: 6px; flex-shrink: 0; }

/* ─────────────────────────────────────────
   BOTTOM CTA
───────────────────────────────────────── */
.efc-cta {
  background: var(--efc-canvas);
  border-top: 1px solid var(--efc-gray);
  padding-block: 40px 64px;
}
.efc-cta__card {
  display: grid;
  grid-template-columns: 1fr;
  gap: 16px;
  align-items: center;
  background: #fff;
  border: 1px solid var(--efc-gray);
