{% style %}
  /* Load Poppins. If your theme blocks @import, add the <link> in theme.liquid instead. */
  @import url('https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap');

  /* Global behavior for this block */
  .bfc-root, .bfc-root * { font-family: 'Poppins', sans-serif; }
  html { scroll-behavior: smooth; }

  /* ===== HERO ===== */
  .bfc-efc-hero { color:#111; position:relative; overflow:hidden; isolation:isolate; }
  .bfc-efc-hero__bg { position:absolute; inset:0; z-index:0; background:linear-gradient(135deg,#ffeda8 0%,#fff 75%); }
  .bfc-efc-hero__wrap { position:relative; z-index:1; max-width:1120px; margin-inline:auto; padding:56px 16px; }
  @media (min-width:768px){ .bfc-efc-hero__wrap{ padding:88px 24px; } }
  .bfc-efc-hero__grid { display:grid; grid-template-columns:1fr; gap:28px; align-items:center; }
  @media (min-width:992px){ .bfc-efc-hero__grid{ grid-template-columns:1.05fr 1fr; gap:48px; } }

  .bfc-pill { display:inline-flex; align-items:center; gap:8px; padding:6px 12px; border-radius:999px; background:#FFE8B3; color:#7A4A00; font-weight:600; font-size:12px; }
  .bfc-efc-hero__title { margin:.6rem 0 .3rem; font-weight:700; line-height:1.05; font-size:clamp(28px,7vw,54px); }
  .bfc-efc-hero__sub { max-width:64ch; color:#555; font-size:clamp(16px,2.2vw,18px); }
  .bfc-efc-hero__ctas { display:flex; flex-wrap:wrap; gap:12px; align-items:center; margin-top:18px; }
  .bfc-btn { display:inline-flex; align-items:center; justify-content:center; gap:.5ch; padding:12px 18px; border-radius:16px; text-decoration:none; border:1px solid transparent; font-weight:600; }
  .bfc-btn--filled { background:#111; color:#fff; }
  .bfc-btn--outline { background:#fff; border-color:#111; color:#111; }
  .bfc-efc-hero__assurance { display:inline-flex; align-items:center; gap:.4rem; color:#6b7280; font-size:13px; }
  .bfc-icon { width:16px; height:16px; }

  .bfc-efc-hero__stats { display:grid; grid-template-columns:repeat(3,1fr); gap:10px; margin-top:22px; align-items:stretch; }
  .bfc-stat { background:rgba(255,255,255,.65); backdrop-filter:saturate(1.1) blur(2px); border:1px solid rgba(17,17,17,.08); border-radius:14px; padding:16px 10px; text-align:center; display:flex; flex-direction:column; justify-content:center; align-items:center; min-height:100px; }
  .bfc-stat__value { font-weight:700; font-size:22px; line-height:1.2; }
  .bfc-stat__label { margin-top:4px; color:#6b7280; font-size:13px; line-height:1.4; }

  .bfc-efc-hero__media { position:relative; }
  .bfc-media-card { aspect-ratio:4/3; border-radius:20px; overflow:hidden; box-shadow:0 14px 40px rgba(0,0,0,.12); border:1px solid rgba(0,0,0,.06); background:#f4f4f4; }
  .bfc-media-card__img { width:100%; height:100%; object-fit:cover; object-position:center; display:block; }

  /* ===== SUBSCRIBE ===== */
  .bfc-subscribe__wrap { max-width:1120px; margin-inline:auto; padding:40px 16px; }
  .bfc-subscribe__title { font-weight:700; font-size:clamp(22px,5vw,32px); margin:0 0 16px; }
  .bfc-subscribe__grid { display:grid; grid-template-columns:1fr; gap:16px; }
  @media (min-width:768px){ .bfc-subscribe__grid{ grid-template-columns:1fr 1fr 1fr; gap:20px; } }
  .bfc-sub-card { border:1px solid rgba(17,17,17,.08); border-radius:16px; background:#fff; padding:16px; display:flex; flex-direction:column; }
  .bfc-sub-card__img { width:100%; height:160px; object-fit:cover; border-radius:12px; margin-bottom:12px; background:#f4f4f4; }
  .bfc-sub-card__title { margin:0 0 6px; font-weight:700; font-size:18px; line-height:1.2; }
  .bfc-sub-card__sub { margin:0; color:#6b7280; font-size:14px; line-height:1.4; }
  .bfc-sub-card__pricing { display:grid; gap:6px; margin:10px 0 6px; }
  .bfc-price__unit { margin-left:2px; font-size:13px; color:#6b7280; }
  .bfc-price--muted { color:#6b7280; font-size:14px; }
  .bfc-pill--save { background:#E8F7E8; color:#107C41; padding:2px 6px; border-radius:999px; font-size:11px; margin-left:6px; }
  .bfc-sub-card__actions { display:flex; flex-wrap:wrap; gap:10px; align-items:center; margin-top:auto; }
  .bfc-btn--sm { padding:8px 12px; font-size:14px; border-radius:12px; }
  .bfc-subscribe__fine { margin-top:16px; color:#6b7280; font-size:12px; }

  /* ===== BOX ===== */
  .bfc-box__wrap { max-width:1120px; margin-inline:auto; padding:48px 16px; }
  .bfc-box__grid { display:grid; grid-template-columns:1fr; gap:20px; align-items:center; }
  @media (min-width:992px){ .bfc-box__grid{ grid-template-columns:1.05fr 1fr; gap:32px; } }
  .bfc-box__title { font-weight:700; font-size:clamp(22px,5vw,36px); margin:0 0 10px; }
  .bfc-box__lead { color:#555; font-size:16px; max-width:60ch; margin:0 0 12px; }
  .bfc-box__list { list-style:none; padding:0; margin:0; display:grid; gap:8px; color:#111; }
  .bfc-media-card--box { aspect-ratio:4/3; border-radius:20px; overflow:hidden; box-shadow:0 14px 40px rgba(0,0,0,.12); border:1px solid rgba(0,0,0,.06); background:#f4f4f4; }

  /* ===== BOTTOM CTA (small wide card) ===== */
  .bfc-shop-cta__wrap { padding:24px 16px 56px; }
  .bfc-shop-cta__card { max-width:960px; margin:0 auto; background:#fff; border:1px solid rgba(17,17,17,.08); border-radius:16px; box-shadow:0 6px 18px rgba(0,0,0,.06); padding:16px; display:grid; grid-template-columns:1fr; gap:12px; align-items:center; }
  @media (min-width:768px){ .bfc-shop-cta__card{ grid-template-columns:1fr auto; padding:18px 20px; } }
  .bfc-shop-cta__title { margin:0; font-size:18px; font-weight:700; color:#111; }
  .bfc-shop-cta__sub { margin:4px 0 0; color:#555; font-size:14px; }
  .bfc-shop-cta__btn { justify-self:start; }
  @media (min-width:768px){ .bfc-shop-cta__btn{ justify-self:end; } }
{% endstyle %}
